import type { Meta, StoryObj } from '@storybook/react-vite';
import { Badge } from './Badge';
import { Button } from '../Button';
import { Space } from '../Space';

const meta = {
  title: 'Components/Badge',
  component: Badge,
  tags: ['autodocs'],
  argTypes: {
    value: { control: 'text' },
    max: { control: 'number' },
    isDot: { control: 'boolean' },
    hidden: { control: 'boolean' },
    type: {
      control: 'inline-radio',
      options: ['primary', 'success', 'warning', 'danger', 'info'],
    },
    showZero: { control: 'boolean' },
    color: { control: 'color' },
    offset: { control: false },
  },
  args: {
    value: 5,
    type: 'danger',
  },
} satisfies Meta<typeof Badge>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Playground: Story = {
  render: (args) => (
    <Badge {...args}>
      <Button>Inbox</Button>
    </Badge>
  ),
};

export const Overflow: Story = {
  name: 'Max and overflow',
  render: () => (
    <Space wrap style={{ gap: 24 }}>
      <Badge value={9}>
        <Button>Mentions</Button>
      </Badge>
      <Badge value={120} max={99}>
        <Button>Comments</Button>
      </Badge>
      <Badge value="new">
        <Button>Updates</Button>
      </Badge>
    </Space>
  ),
};

export const Dot: Story = {
  name: 'Dot indicator',
  render: () => (
    <Space wrap style={{ gap: 24 }}>
      <Badge isDot>
        <Button>Notifications</Button>
      </Badge>
      <Badge isDot type="warning">
        <Button>Settings</Button>
      </Badge>
    </Space>
  ),
};

export const Types: Story = {
  render: () => (
    <Space wrap style={{ gap: 24 }}>
      <Badge value={1} type="primary">
        <Button>Primary</Button>
      </Badge>
      <Badge value={2} type="success">
        <Button>Success</Button>
      </Badge>
      <Badge value={3} type="warning">
        <Button>Warning</Button>
      </Badge>
      <Badge value={4} type="danger">
        <Button>Danger</Button>
      </Badge>
      <Badge value={5} type="info">
        <Button>Info</Button>
      </Badge>
    </Space>
  ),
};

import {
  type CSSProperties,
  forwardRef,
  type HTMLAttributes,
  type ReactNode,
} from 'react';
import { cls, useNamespace } from '../../utils';

export type BadgeType = 'primary' | 'success' | 'warning' | 'danger' | 'info';

export interface BadgeProps extends HTMLAttributes<HTMLDivElement> {
  /** Displayed value. */
  value?: number | string;
  /** Maximum value; numbers above it render as `{max}+`. */
  max?: number;
  /** Render a small dot instead of the value. */
  isDot?: boolean;
  /** Hide the badge. */
  hidden?: boolean;
  /** Color variant. */
  type?: BadgeType;
  /** Show the badge even when the value is zero. */
  showZero?: boolean;
  /** Custom background color, overriding the type color. */
  color?: string;
  /** Offset of the badge, as `[x, y]` in pixels. */
  offset?: [number, number];
  children?: ReactNode;
}

export const Badge = forwardRef<HTMLDivElement, BadgeProps>(function Badge(props, ref) {
  const {
    value,
    max = 99,
    isDot = false,
    hidden = false,
    type = 'danger',
    showZero = false,
    color,
    offset,
    className,
    children,
    ...rest
  } = props;

  const ns = useNamespace('badge');

  // Numbers over `max` collapse to "{max}+".
  const content: ReactNode = (() => {
    if (isDot) return undefined;
    if (typeof value === 'number' && typeof max === 'number' && value > max) {
      return `${max}+`;
    }
    return value;
  })();

  // Hide when explicitly hidden, or when the value is an empty/zero number and
  // showZero is not set (dots always show unless hidden).
  const isZero = value === 0 || value === '0';
  const isEmpty = value === undefined || value === null || value === '';
  const shouldShow = !hidden && !isEmpty && (isDot || showZero || !isZero);

  const badgeStyle: CSSProperties | undefined = (() => {
    const style: CSSProperties = {};
    if (color) style.backgroundColor = color;
    if (offset) {
      const [x, y] = offset;
      style.transform = `translateY(-50%) translateX(100%) translate(${x}px, ${y}px)`;
    }
    return Object.keys(style).length ? style : undefined;
  })();

  const badge = shouldShow ? (
    <sup
      className={cls(
        ns.e('content'),
        ns.em('content', type),
        ns.is('fixed', children != null),
        ns.is('dot', isDot),
      )}
      style={badgeStyle}
    >
      {content}
    </sup>
  ) : null;

  // Without children the badge renders inline (no positioned wrapper needed).
  if (children == null) {
    return (
      <div ref={ref} className={cls(ns.b(), className)} {...rest}>
        {badge}
      </div>
    );
  }

  return (
    <div ref={ref} className={cls(ns.b(), className)} {...rest}>
      {children}
      {badge}
    </div>
  );
});

.ec-badge {
  --ec-badge-bg-color: var(--ec-color-danger);
  --ec-badge-text-color: var(--ec-color-danger-contrast);
  --ec-badge-size: 18px;
  --ec-badge-padding: 6px;
  --ec-badge-font-size: 12px;
  --ec-badge-radius: 10px;
  --ec-badge-dot-size: 8px;
  --ec-badge-dot-radius: 50%;

  position: relative;
  display: inline-block;
  box-sizing: border-box;
  font-family: inherit;
  line-height: 1;
  vertical-align: middle;
}

.ec-badge__content {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  box-sizing: border-box;
  height: var(--ec-badge-size);
  padding: 0 var(--ec-badge-padding);
  font-size: var(--ec-badge-font-size);
  font-weight: var(--ec-font-weight-primary);
  line-height: 1;
  white-space: nowrap;
  text-align: center;
  color: var(--ec-badge-text-color);
  background-color: var(--ec-badge-bg-color);
  border: 1px solid var(--ec-color-white);
  border-radius: var(--ec-badge-radius);
}

/* When attached to children, the badge floats over the top-right corner. */
.ec-badge__content.is-fixed {
  position: absolute;
  top: 0;
  right: 0;
  transform: translateY(-50%) translateX(100%);
  transform-origin: 100% 0%;
  z-index: 1;
}

.ec-badge__content.is-dot {
  width: var(--ec-badge-dot-size);
  height: var(--ec-badge-dot-size);
  padding: 0;
  border-radius: var(--ec-badge-dot-radius);
}

.ec-badge__content.is-fixed.is-dot {
  right: 5px;
}

/* ---- Color variants: contrast text on the per-type fill ---- */
.ec-badge__content--primary {
  --ec-badge-bg-color: var(--ec-color-primary);
  --ec-badge-text-color: var(--ec-color-primary-contrast);
}
.ec-badge__content--success {
  --ec-badge-bg-color: var(--ec-color-success);
  --ec-badge-text-color: var(--ec-color-success-contrast);
}
.ec-badge__content--warning {
  --ec-badge-bg-color: var(--ec-color-warning);
  --ec-badge-text-color: var(--ec-color-warning-contrast);
}
.ec-badge__content--danger {
  --ec-badge-bg-color: var(--ec-color-danger);
  --ec-badge-text-color: var(--ec-color-danger-contrast);
}
.ec-badge__content--info {
  --ec-badge-bg-color: var(--ec-color-info);
  --ec-badge-text-color: var(--ec-color-info-contrast);
}
